if (rgb.r == fMax) {
hsl.x = (rgb.g - rgb.b) / denom;
} else if (rgb.g == fMax) {
hsl.x = (rgb.b - rgb.r) / denom + (1.0 / 3.0);
} else if (rgb.b == fMax) {
hsl.x = (rgb.r - rgb.g) / denom + (2.0 / 3.0);
}
if (hsl.x < 0.0) {
hsl.x += 1.0;
}
if (hsl.x > 1.0) {
hsl.x -= 1.0;
}
return hsl;
